import type { CareerQuestion } from "./rrt-questions";

export const ptaQuestionsBatch8: CareerQuestion[] = [
  { id: "pta-1481", stem: "A PTA is performing a Berg Balance Scale assessment. The patient scores 42/56. What does this indicate?", options: ["No fall risk", "Moderate fall risk — scores between 41-56 indicate low-moderate risk; below 41 indicates high fall risk", "Maximum fall risk", "Cannot interpret the score"], correctIndex: 1, rationale: "BBS interpretation: 0-20 = wheelchair bound, 21-40 = walking with assistance (high fall risk), 41-56 = independent (low-moderate fall risk). Score of 42 = low-moderate fall risk.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "BBS interpretation" },
  { id: "pta-1482", stem: "A geriatric patient has difficulty rising from a chair. Which exercise specifically targets this functional deficit?", options: ["Bicep curls", "Sit-to-stand repetitions (chair squats) targeting quadriceps, hip extensors, and ankle dorsiflexors", "Hamstring curls", "Shoulder press"], correctIndex: 1, rationale: "Sit-to-stand training: targets quadriceps, gluteus maximus, and ankle dorsiflexors. Progress by lowering chair height, adding repetitions, increasing speed, and reducing arm use.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "sit-to-stand exercise" },
  { id: "pta-1483", stem: "An elderly patient has sarcopenia. What is the MOST important intervention?", options: ["Only aerobic exercise", "Progressive resistance training combined with adequate protein intake to build and maintain muscle mass", "Only stretching", "Only walking"], correctIndex: 1, rationale: "Sarcopenia management: progressive resistance training (2-3x/week, moderate intensity), adequate protein intake (1.0-1.2 g/kg/day), and vitamin D supplementation if deficient.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "sarcopenia intervention" },
  { id: "pta-1484", stem: "A geriatric patient with Parkinson's disease uses a rollator walker. What additional safety feature is important?", options: ["No additional features", "Handbrakes on the rollator and laser line attachment for visual cueing to overcome freezing of gait", "Remove the brakes", "Use a standard walker instead"], correctIndex: 1, rationale: "PD rollator safety: handbrakes essential (prevent runaway), laser line attachment for visual cueing (freezing), and U-step walker (reverse braking) may be safer than standard rollators.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "PD rollator safety" },
  { id: "pta-1485", stem: "Which balance strategy do older adults typically use when experiencing a large perturbation (push)?", options: ["Ankle strategy", "Stepping strategy — taking a step to widen the base of support and prevent falling", "Hip strategy", "No strategy"], correctIndex: 1, rationale: "Balance strategies: ankle (small perturbations), hip (moderate perturbations), stepping (large perturbations). Older adults may have impaired stepping reactions, increasing fall risk.", difficulty: 2, category: "Geriatric Rehabilitation", topic: "stepping strategy" },
  { id: "pta-1486", stem: "A geriatric patient has been prescribed a home exercise program. What is the MOST important factor for long-term adherence?", options: ["Complex exercises", "Make the program simple, meaningful (connected to personal goals), and convenient; include written/visual instructions and regular follow-up", "Maximum number of exercises", "Only unsupervised exercise"], correctIndex: 1, rationale: "HEP adherence: simplicity (few exercises), personal meaningfulness (connect to goals), convenience (fits into routine), clear instructions, regular follow-up, and self-monitoring tools.", difficulty: 1, category: "Geriatric Rehabilitation", topic: "HEP adherence" },
  { id: "pta-1487", stem: "A child with spastic hemiplegic CP is being assessed for functional mobility. Which classification system is used?", options: ["FIM", "Gross Motor Function Classification System (GMFCS) — 5 levels based on self-initiated movement and need for assistive devices", "Berg Balance Scale", "Manual Muscle Testing"], correctIndex: 1, rationale: "GMFCS: 5 levels (I-V). Level I: walks without limitations. Level V: transported in wheelchair. Age-specific descriptors. Predicts future motor function and guides intervention.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "GMFCS classification" },
  { id: "pta-1488", stem: "At what age does a typically developing child demonstrate head control in supported sitting?", options: ["Birth", "3-4 months — steady head control in supported sitting with minimal head bobbing", "8 months", "12 months"], correctIndex: 1, rationale: "Head control milestones: brief head lifting in prone (1 month), sustained head lift (2 months), steady head in supported sitting (3-4 months), and full head control in all positions (5-6 months).", difficulty: 1, category: "Pediatric Rehabilitation", topic: "head control milestone" },
  { id: "pta-1489", stem: "A child with Duchenne muscular dystrophy is at stage 3 (walking with difficulty). What is the PT focus?", options: ["Maximum strength training", "Maintain function as long as possible: gentle ROM, contracture prevention, orthotic support, and planning for wheelchair transition", "Running exercises", "No PT needed at this stage"], correctIndex: 1, rationale: "DMD Stage 3: maintain walking ability, prevent contractures (stretching hip flexors, ITB, ankle PF), night splinting (AFOs), gentle strengthening (avoid eccentric overload), and plan for wheelchair.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "DMD stage 3 PT" },
  { id: "pta-1490", stem: "A premature infant in the NICU demonstrates physiological stress cues. Which signs indicate the infant is stressed?", options: ["Relaxed posture", "Color changes (mottling, cyanosis), yawning, hiccupping, finger splaying, arching, and vital sign changes", "Smooth movements", "Alert and calm state"], correctIndex: 1, rationale: "NICU stress cues: color changes, yawning, hiccupping, sneezing, finger splaying, arching, gaze aversion, state changes, vital sign instability. Reduce stimulation and allow recovery.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "NICU stress cues" },
  { id: "pta-1491", stem: "A child with a brachial plexus injury (Erb's palsy, C5-C6) demonstrates which arm position?", options: ["Arm overhead", "Waiter's tip position: shoulder internally rotated, adducted, elbow extended, forearm pronated, and wrist flexed", "Normal arm position", "Arm in full flexion"], correctIndex: 1, rationale: "Erb's palsy (C5-C6): waiter's tip position — shoulder IR/adduction, elbow extension, forearm pronation, wrist flexion. Affects deltoid, biceps, brachialis, and supinator.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "Erb's palsy position" },
  { id: "pta-1492", stem: "Which primitive reflex causes the infant to extend the arm on the face side when the head is turned?", options: ["Moro reflex", "Asymmetric tonic neck reflex (ATNR) — 'fencer's position' with arm extension on the face side and flexion on the skull side", "Rooting reflex", "Galant reflex"], correctIndex: 1, rationale: "ATNR: head turning causes arm/leg extension on the face side and flexion on the skull side. Appears at birth, integrates by 4-6 months. Persistent ATNR interferes with midline activities.", difficulty: 1, category: "Pediatric Rehabilitation", topic: "ATNR" },
  { id: "pta-1493", stem: "A child with idiopathic toe walking is being treated in PT. Which intervention is evidence-based?", options: ["Only observation", "Serial casting to increase ankle dorsiflexion ROM, stretching, heel cord stretching, and gait training with verbal/tactile cues for heel strike", "Surgery immediately", "No intervention needed"], correctIndex: 1, rationale: "Idiopathic toe walking: serial casting (progressive dorsiflexion), stretching (gastrocnemius/soleus), AFOs, gait training with cueing, and strengthening of dorsiflexors.", difficulty: 2, category: "Pediatric Rehabilitation", topic: "toe walking treatment" },
  { id: "pta-1494", stem: "A patient with a complete T1 SCI has full upper extremity function. What is the expected level of wheelchair mobility?", options: ["Power wheelchair only", "Fully independent manual wheelchair propulsion including wheelies, curb management, and advanced skills", "Cannot propel a wheelchair", "Needs power assist wheels"], correctIndex: 1, rationale: "T1 SCI: full UE function including hand intrinsics. Fully independent manual wheelchair user: propulsion, transfers, wheelies, curb management, and terrain negotiation.", difficulty: 2, category: "Neurological Rehabilitation", topic: "T1 SCI wheelchair independence" },
  { id: "pta-1495", stem: "A patient with a traumatic brain injury is at Rancho Level VIII (purposeful, appropriate). What are the remaining deficits?", options: ["No remaining deficits", "Subtle deficits in processing speed, stress tolerance, judgment in novel situations, and abstract reasoning under pressure", "Unable to function in community", "Complete dependence in ADLs"], correctIndex: 1, rationale: "Rancho VIII: purposeful, appropriate, but with subtle deficits — processing speed, stress tolerance, novel situation judgment, abstract reasoning, and multitasking under pressure.", difficulty: 2, category: "Neurological Rehabilitation", topic: "TBI Rancho VIII" },
  { id: "pta-1496", stem: "A patient with hemiplegia demonstrates shoulder subluxation. Which intervention helps reduce subluxation?", options: ["Arm sling at all times", "NMES/FES to the supraspinatus and posterior deltoid, proper positioning, and arm support during sitting/standing", "Forceful shoulder exercises", "Nothing can be done"], correctIndex: 1, rationale: "Shoulder subluxation management: NMES/FES (supraspinatus, posterior deltoid), proper positioning (arm supported), arm trough/lap tray when sitting, sling only during ambulation, and avoid traction.", difficulty: 2, category: "Neurological Rehabilitation", topic: "shoulder subluxation treatment" },
  { id: "pta-1497", stem: "A patient with ALS is experiencing difficulty breathing while lying flat. What does this indicate?", options: ["Normal progression", "Diaphragm weakness — orthopnea (difficulty breathing supine) is an early sign of respiratory muscle involvement in ALS", "Anxiety only", "Unrelated to ALS"], correctIndex: 1, rationale: "ALS orthopnea: indicates diaphragm weakness (early respiratory involvement). Important milestone — may need nocturnal BiPAP, FVC monitoring, and pulmonary referral.", difficulty: 2, category: "Neurological Rehabilitation", topic: "ALS respiratory signs" },
  { id: "pta-1498", stem: "A patient post-stroke demonstrates the flexion synergy pattern in the upper extremity. What movements are included?", options: ["Shoulder extension, elbow extension", "Scapular retraction/elevation, shoulder abduction/ER, elbow flexion, forearm supination, wrist/finger flexion", "Isolated finger extension", "Normal voluntary movement"], correctIndex: 1, rationale: "UE flexion synergy: scapular retraction/elevation, shoulder abduction + ER, elbow flexion, forearm supination, and wrist/finger flexion. The patient cannot move outside this pattern.", difficulty: 2, category: "Neurological Rehabilitation", topic: "UE flexion synergy" },
  { id: "pta-1499", stem: "A patient with a central vestibular disorder demonstrates which type of nystagmus?", options: ["Fatiguing horizontal nystagmus", "Non-fatiguing nystagmus that may be vertical, direction-changing, or purely torsional — does not follow peripheral patterns", "No nystagmus", "Only horizontal nystagmus"], correctIndex: 1, rationale: "Central vestibular nystagmus: may be vertical (upbeat/downbeat), direction-changing, purely torsional, non-fatiguing, and does not follow the rules of peripheral nystagmus. Requires medical workup.", difficulty: 3, category: "Neurological Rehabilitation", topic: "central vestibular nystagmus" },
  { id: "pta-1500", stem: "A patient with peripheral neuropathy has loss of protective sensation in the feet. What Semmes-Weinstein monofilament result indicates loss of protective sensation?", options: ["2.83 monofilament", "5.07 monofilament (10g force) — inability to feel this indicates loss of protective sensation and increased ulcer risk", "6.65 monofilament", "All monofilaments"], correctIndex: 1, rationale: "Semmes-Weinstein 5.07 monofilament (10g): inability to perceive this indicates loss of protective sensation. Test 10 plantar foot sites. Key screening for diabetic neuropathy ulcer risk.", difficulty: 2, category: "Neurological Rehabilitation", topic: "monofilament testing" },
  { id: "pta-1501", stem: "A patient post-TKR has significant quadriceps inhibition (arthrogenic muscle inhibition). Which intervention is MOST effective?", options: ["Only passive stretching", "NMES combined with volitional quadriceps exercise to overcome inhibition and restore quad activation", "Only ice", "Wait for it to resolve naturally"], correctIndex: 1, rationale: "Arthrogenic muscle inhibition post-TKR: NMES combined with volitional exercise overcomes neural inhibition. Biofeedback, cryotherapy-assisted exercise, and blood flow restriction training also help.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "arthrogenic inhibition" },
  { id: "pta-1502", stem: "A patient with an anterior hip replacement (anterior approach) has which precaution?", options: ["Same as posterior approach", "Avoid combined hip extension and external rotation — opposite of posterior approach precautions", "No precautions needed", "Only flexion restriction"], correctIndex: 1, rationale: "Anterior approach THR: avoid hip extension + ER (stresses the anterior capsule repair). Opposite of posterior approach. Some surgeons have minimal or no precautions with anterior approach.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "anterior THR precautions" },
  { id: "pta-1503", stem: "A patient with a patellar tendon rupture repair is at 6 weeks. What activity is appropriate?", options: ["Full squats", "Progressive weight-bearing, gentle AROM (avoiding end-range extension against resistance), and pool walking if wound is healed", "Running", "No activity until 12 weeks"], correctIndex: 1, rationale: "Patellar tendon repair at 6 weeks: progressive WB, gentle AROM within protected range, avoid resisted terminal extension (stress on repair), stationary bike (limited arc), and pool walking.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "patellar tendon repair rehab" },
  { id: "pta-1504", stem: "A patient with a lumbar microdiscectomy is 4 weeks post-surgery. What exercise is appropriate?", options: ["Heavy deadlifts", "Walking program, gentle core stabilization (abdominal bracing, pelvic tilts), and lower extremity stretching while maintaining neutral spine", "Aggressive trunk flexion", "No exercise until 3 months"], correctIndex: 1, rationale: "Post-microdiscectomy 4 weeks: walking program (primary aerobic), gentle core stabilization, LE stretching, neutral spine education, and avoid excessive trunk flexion/rotation/heavy lifting.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "microdiscectomy rehab" },
  { id: "pta-1505", stem: "A patient with a Bankart repair demonstrates apprehension when the shoulder is placed in abduction and external rotation. What test is this?", options: ["Yergason's test", "Apprehension test (anterior instability test) — positive if the patient demonstrates anxiety or resistance in the abducted/ER position", "Speed's test", "Drop arm test"], correctIndex: 1, rationale: "Anterior apprehension test: arm abducted 90° and externally rotated. Positive = apprehension, guarding, or resistance (not just pain). Indicates anterior glenohumeral instability.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "apprehension test" },
  { id: "pta-1506", stem: "A patient with a tibial plateau fracture is at 8 weeks and cleared for progressive weight-bearing. What is the rehabilitation focus?", options: ["Immediate running", "Progressive weight-bearing, knee ROM (flexion and extension), quadriceps strengthening, and functional activity training", "Only upper body exercise", "No rehabilitation needed"], correctIndex: 1, rationale: "Tibial plateau fracture at 8 weeks with WB clearance: progressive WB (heel to toe walking), knee ROM, quad strengthening (OKC and CKC), proprioception, and gradual functional activities.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "tibial plateau rehab" },
  { id: "pta-1507", stem: "A patient with a shoulder labral tear demonstrates a positive O'Brien test. What structure is being tested?", options: ["Rotator cuff", "Superior labrum (SLAP lesion) — pain with resisted shoulder flexion in adduction/IR that decreases in ER", "ACL", "Biceps tendon only"], correctIndex: 1, rationale: "O'Brien test (active compression): arm flexed 90°, adducted 10-15°, IR (thumb down), resist flexion (pain). Repeat in ER (thumb up): less pain. Positive = SLAP lesion.", difficulty: 3, category: "Orthopedic Rehabilitation", topic: "O'Brien test SLAP" },
  { id: "pta-1508", stem: "A patient recovering from a total hip replacement is learning to use a cane. When should the cane be discontinued?", options: ["After 2 weeks", "When the patient demonstrates a non-antalgic gait pattern, adequate hip abductor strength, and confidence without the device", "Never — always use a cane", "After 1 day"], correctIndex: 1, rationale: "Cane discontinuation criteria: non-antalgic gait (no limp), adequate hip abductor strength (no Trendelenburg), full weight-bearing tolerance, confidence, and surgeon clearance.", difficulty: 1, category: "Orthopedic Rehabilitation", topic: "cane discontinuation criteria" },
  { id: "pta-1509", stem: "A patient with a chronic ankle instability needs proprioceptive training. What is the progression?", options: ["Start on the most unstable surface", "Bilateral stance (stable) → single leg (stable) → bilateral (unstable) → single leg (unstable) → add perturbations and sport-specific tasks", "Only walking on flat surfaces", "No progression needed"], correctIndex: 1, rationale: "Proprioceptive training progression: bilateral stable → single-leg stable → bilateral unstable (foam, wobble board) → single-leg unstable → perturbations → sport-specific dynamic tasks.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "proprioceptive progression" },
  { id: "pta-1510", stem: "A patient with a calcaneal fracture is at 10 weeks and transitioning to weight-bearing. What exercise is important?", options: ["Jumping", "Heel cord stretching, ankle ROM, intrinsic foot strengthening, and progressive weight-bearing with arch support/custom orthotic", "Running immediately", "No exercises needed"], correctIndex: 1, rationale: "Calcaneal fracture at 10 weeks with WB: heel cord stretching (Achilles often tight), ankle ROM, intrinsic foot strengthening, progressive WB, arch support, and gait training.", difficulty: 2, category: "Orthopedic Rehabilitation", topic: "calcaneal fracture rehab" },
  { id: "pta-1511", stem: "A PTA is teaching a patient about body mechanics for lifting. What is the correct distance the feet should be apart?", options: ["Feet together", "Shoulder-width apart with one foot slightly ahead (staggered stance) for a wide, stable base of support", "3 feet apart", "Standing on one leg"], correctIndex: 1, rationale: "Lifting body mechanics: feet shoulder-width apart, staggered stance (one foot slightly forward), bend knees, maintain neutral spine, engage core, and keep the load close.", difficulty: 1, category: "Patient Education", topic: "lifting foot position" },
  { id: "pta-1512", stem: "A patient asks the PTA about the difference between heat and ice for pain. When should heat be used?", options: ["Acute injuries only", "Chronic conditions, muscle stiffness, and before stretching — heat increases tissue extensibility and blood flow", "Never use heat", "Always use heat for everything"], correctIndex: 1, rationale: "Heat indications: chronic conditions, muscle stiffness, before stretching, joint stiffness. Contraindications: acute injury (first 48-72 hours), active inflammation, sensory deficits, over malignancy.", difficulty: 1, category: "Patient Education", topic: "heat vs ice" },
  { id: "pta-1513", stem: "When educating a patient about the importance of warm-up before exercise, what should be included?", options: ["Skip warm-up — go straight to exercise", "5-10 minutes of low-intensity aerobic activity to increase blood flow, muscle temperature, and joint lubrication before more intense exercise", "Static stretching only", "Maximum effort from the start"], correctIndex: 1, rationale: "Warm-up: 5-10 minutes of low-intensity aerobic activity (walking, cycling) to increase muscle temperature, blood flow, joint lubrication, and neural readiness before exercise.", difficulty: 1, category: "Patient Education", topic: "warm-up importance" },
  { id: "pta-1514", stem: "A patient needs education about proper posture during standing activities. What is the key alignment?", options: ["Lean forward", "Ears over shoulders, shoulders over hips, hips over knees, knees over ankles — maintaining natural spinal curves", "Hyperlordosis is ideal", "Stand with locked knees"], correctIndex: 1, rationale: "Ideal standing posture: ear-shoulder-hip-knee-ankle alignment, natural spinal curves maintained, weight evenly distributed, core engaged, and avoid prolonged static standing.", difficulty: 1, category: "Patient Education", topic: "standing posture" },
  { id: "pta-1515", stem: "When educating a patient about safe bathroom transfers, what is the MOST important safety equipment?", options: ["Bath mat only", "Grab bars mounted to wall studs (near toilet and tub/shower) combined with non-slip surfaces and adequate lighting", "Towel bar for support", "Nothing — be careful"], correctIndex: 1, rationale: "Bathroom safety essentials: grab bars (mounted to studs, not towel bars), non-slip mat/strips, raised toilet seat (if needed), shower chair, handheld shower, and adequate lighting.", difficulty: 1, category: "Patient Education", topic: "bathroom safety equipment" },
  { id: "pta-1516", stem: "A patient recovering from a cardiac event needs to understand the warning signs to stop exercise. What should be reported?", options: ["Mild sweating", "Chest pain/pressure, unusual shortness of breath, dizziness, irregular heartbeat, nausea, and excessive fatigue", "Normal increased heart rate", "Slight muscle soreness"], correctIndex: 1, rationale: "Cardiac exercise warning signs (stop immediately): chest pain/pressure, unusual dyspnea, dizziness/lightheadedness, irregular heartbeat, nausea, excessive fatigue, and diaphoresis.", difficulty: 1, category: "Patient Education", topic: "cardiac exercise warning signs" },
  { id: "pta-1517", stem: "A PTA is documenting a treatment session using the SOAP format. The 'A' (Assessment) section should include:", options: ["Patient's self-report", "Clinical interpretation of objective findings, progress toward goals, barriers to progress, and justification for continued treatment", "Exercise parameters", "Treatment plan for next session"], correctIndex: 1, rationale: "Assessment section: clinical reasoning/interpretation, progress toward goals (improved/stable/declined), barriers identified, treatment effectiveness analysis, and justification for continued services.", difficulty: 1, category: "Documentation", topic: "SOAP assessment section" },
  { id: "pta-1518", stem: "What does the abbreviation 'SBA' mean in physical therapy documentation?", options: ["Stand-by assistance only", "Standby assist — the therapist is within arm's reach for safety but does not provide physical assistance", "Sit beside and assist", "Standard basic assessment"], correctIndex: 1, rationale: "SBA = Standby Assist: the therapist is near the patient (within arm's reach) for safety but provides no physical contact. Between supervision (can be out of arm's reach) and CGA (hands-on).", difficulty: 1, category: "Documentation", topic: "SBA abbreviation" },
  { id: "pta-1519", stem: "A PTA is writing a progress note and needs to report a change in the patient's condition. What must be included?", options: ["Only that a change occurred", "Specific changes observed, comparison to previous status, impact on treatment plan, communication with PT, and any modifications made", "Only a phone call to the PT", "Nothing — changes are normal"], correctIndex: 1, rationale: "Reporting status change: specific objective changes, comparison to prior status, functional impact, PT notification, plan modifications, and date/time of communication with supervising PT.", difficulty: 1, category: "Documentation", topic: "status change documentation" },
  { id: "pta-1520", stem: "Which documentation practice helps protect against liability?", options: ["Minimal documentation", "Thorough, objective, and timely documentation including patient education, response to treatment, and informed consent", "Delayed documentation is fine", "Copy previous notes"], correctIndex: 1, rationale: "Legal protection: thorough documentation (what was done, patient response), timely (same day), objective language, informed consent documented, and incident reports for any adverse events.", difficulty: 1, category: "Documentation", topic: "documentation liability protection" },
  { id: "pta-1521", stem: "A PTA is performing sterile wound irrigation. Which solution is commonly used?", options: ["Tap water", "Normal saline (0.9% NaCl) at body temperature — physiologically compatible and effective for wound cleansing", "Hydrogen peroxide", "Alcohol solution"], correctIndex: 1, rationale: "Wound irrigation: normal saline (0.9% NaCl) at body temperature. Appropriate pressure (4-15 psi using 35cc syringe with 19-gauge angiocatheter). Avoid cytotoxic solutions (peroxide, Betadine) on clean wounds.", difficulty: 2, category: "Infection Prevention", topic: "wound irrigation" },
  { id: "pta-1522", stem: "A PTA is treating a patient in a skilled nursing facility during a norovirus outbreak. What enhanced precautions are needed?", options: ["Standard precautions only", "Contact precautions with enhanced environmental cleaning (bleach-based disinfectant), soap and water hand hygiene, and possible cohorting of patients", "Airborne precautions", "No additional precautions"], correctIndex: 1, rationale: "Norovirus: contact precautions, soap and water hand hygiene (alcohol-based rubs less effective), bleach-based environmental disinfection, cohorting, and close monitoring for symptoms.", difficulty: 2, category: "Infection Prevention", topic: "norovirus precautions" },
  { id: "pta-1523", stem: "When treating a wound with a hydrogel dressing, what is the primary purpose?", options: ["Remove excess moisture", "Provide moisture to a dry wound bed to promote autolytic debridement and create a moist healing environment", "Absorb large drainage", "Provide compression"], correctIndex: 1, rationale: "Hydrogel: provides moisture to dry wounds, promotes autolytic debridement, soothes painful wounds, and maintains a moist healing environment. Not for heavily exuding wounds.", difficulty: 2, category: "Infection Prevention", topic: "hydrogel dressing purpose" },
  { id: "pta-1524", stem: "A patient with a wound has undermining documented at 3 o'clock and 6 o'clock positions. What does undermining mean?", options: ["Wound is healing", "Tissue destruction extending under the wound edge in a lateral direction — like a cave under the wound margin", "Normal wound appearance", "The wound is superficial"], correctIndex: 1, rationale: "Undermining: tissue destruction extending laterally under intact wound edges. Documented by clock position and depth. Differs from tunneling (a narrow channel extending from the wound).", difficulty: 2, category: "Infection Prevention", topic: "wound undermining" },
  { id: "pta-1525", stem: "A PTA observes a patient exhibiting signs of anaphylaxis after application of a topical agent. What should be done?", options: ["Continue treatment", "Stop treatment immediately, call 911, assist with epinephrine auto-injector if available, maintain airway, and monitor vital signs", "Apply more of the topical agent", "Give the patient water"], correctIndex: 1, rationale: "Anaphylaxis emergency: stop the causative agent, call 911, epinephrine (if available), maintain airway/breathing, monitor vitals, position supine with legs elevated (if not contraindicated).", difficulty: 1, category: "Patient Safety", topic: "anaphylaxis response" },
  { id: "pta-1526", stem: "A patient on anticoagulation therapy (Coumadin) falls during PT. The patient hits their head but appears asymptomatic. What should the PTA do?", options: ["Continue therapy", "Stop therapy, assess neurological status, notify the physician immediately (increased bleeding risk with head trauma on anticoagulants), and monitor closely", "Apply ice and continue", "Document only and continue"], correctIndex: 1, rationale: "Head trauma on anticoagulants: increased risk of intracranial bleeding. Stop therapy, neurological assessment, notify physician immediately, monitor for delayed symptoms, and complete incident report.", difficulty: 2, category: "Patient Safety", topic: "head trauma on anticoagulants" },
  { id: "pta-1527", stem: "A patient demonstrates a positive Babinski sign. What does this indicate in an adult?", options: ["Normal finding", "Upper motor neuron lesion — great toe extends and other toes fan out when the plantar surface is stroked", "Lower motor neuron lesion", "Peripheral neuropathy"], correctIndex: 1, rationale: "Positive Babinski in adults: abnormal — indicates upper motor neuron lesion (stroke, SCI, MS). Great toe extends (dorsiflexion), other toes fan. Normal in infants up to 12-24 months.", difficulty: 2, category: "Patient Safety", topic: "Babinski sign" },
  { id: "pta-1528", stem: "A patient with hepatitis C is receiving PT. What precautions are required?", options: ["Airborne precautions", "Standard precautions — hepatitis C is transmitted through blood; standard blood/body fluid precautions are sufficient", "Contact precautions", "No precautions needed"], correctIndex: 1, rationale: "Hepatitis C: blood-borne pathogen. Standard precautions are sufficient: gloves for blood/body fluid contact, hand hygiene, sharps precautions, and barrier protection if splash risk.", difficulty: 1, category: "Patient Safety", topic: "hepatitis C precautions" },
  { id: "pta-1529", stem: "A patient's heart rate is 150 bpm at rest before therapy. Should the PTA proceed?", options: ["Yes — begin immediately", "No — resting HR >120-130 bpm is a contraindication to exercise; notify the physician and do not begin therapy", "Start with light exercise", "Only upper body exercise"], correctIndex: 1, rationale: "Resting HR >120-130 bpm: do not exercise. May indicate cardiac pathology, dehydration, infection, or medication effect. Notify the physician and document. Other contraindications: unstable angina, acute MI.", difficulty: 1, category: "Patient Safety", topic: "resting tachycardia contraindication" },
  { id: "pta-1530", stem: "Which ethical principle requires that the PTA treat all patients fairly and equitably regardless of background?", options: ["Autonomy", "Justice — fair and equitable treatment of all patients regardless of race, gender, socioeconomic status, or diagnosis", "Beneficence", "Veracity"], correctIndex: 1, rationale: "Justice: fair and equitable distribution of healthcare resources and treatment. No discrimination based on race, gender, age, socioeconomic status, diagnosis, or personal characteristics.", difficulty: 1, category: "Professional Ethics", topic: "justice principle" },
  { id: "pta-1531", stem: "A PTA is asked to treat a patient whose needs are beyond the PTA's training. What is the ethical obligation?", options: ["Treat the patient anyway", "Inform the supervising PT, request additional training or supervision, and if not competent, refer to an appropriately qualified clinician", "Refuse to treat completely", "Ask the patient for guidance"], correctIndex: 1, rationale: "Practice within competence: inform the PT, request training/supervision, and if the intervention is beyond the PTA's skill level, refer appropriately. Protecting patient safety is paramount.", difficulty: 1, category: "Professional Ethics", topic: "competence boundaries" },
  { id: "pta-1532", stem: "The APTA Code of Ethics states that PTAs should advocate for which group?", options: ["Only their employer", "Patients, the profession, and the community — advocating for access to quality physical therapy services for all", "Only themselves", "Only other PTAs"], correctIndex: 1, rationale: "APTA ethical advocacy: for patients (quality care, access), the profession (maintaining standards), and the community (health promotion, policy, and pro bono services).", difficulty: 1, category: "Professional Ethics", topic: "PTA advocacy" },
  { id: "pta-1533", stem: "A PTA discovers an error in their documentation from a previous treatment session. What is the correct way to correct it?", options: ["Erase the error", "Draw a single line through the error, write the correction, date and initial the change — late entries should be labeled as such", "White-out the error", "Remove the page"], correctIndex: 1, rationale: "Documentation correction: single line through error (keep original visible), write correction, date and initial. Never erase, white-out, or remove pages. Late entries: label with current date and 'late entry'.", difficulty: 1, category: "Professional Ethics", topic: "documentation correction" },
  { id: "pta-1534", stem: "A patient asks the PTA about the benefits of a specific dietary supplement. How should the PTA respond?", options: ["Recommend specific supplements", "Explain that dietary supplement advice is outside the PTA's scope of practice and recommend consulting a registered dietitian or physician", "Share personal supplement preferences", "Discourage all supplements"], correctIndex: 1, rationale: "Supplement advice is outside PTA scope. Refer to a registered dietitian or physician. The PTA can educate on general nutrition principles related to exercise and recovery within PT scope.", difficulty: 1, category: "Professional Ethics", topic: "supplement scope" },
  { id: "pta-1535", stem: "A patient with a recent hip fracture is being assessed for discharge readiness. Which functional criteria must be met?", options: ["Only able to stand", "Safe transfers, functional ambulation (with appropriate device), stair negotiation (if needed at home), and ability to perform basic ADLs with available assistance", "Only range of motion goals", "Only strength goals"], correctIndex: 1, rationale: "Discharge readiness: safe transfers (bed, toilet, chair), functional ambulation for home environment, stair negotiation (if applicable), basic ADLs, adequate caregiver support, and home equipment in place.", difficulty: 1, category: "Clinical Case Scenarios", topic: "discharge readiness criteria" },
  { id: "pta-1536", stem: "A patient with a traumatic above-knee amputation is being fitted for a prosthesis. What is the optimal time for prosthetic fitting?", options: ["Immediately post-amputation", "Once the residual limb has healed, edema is controlled, and limb shaping has occurred — typically 6-8 weeks for definitive prosthesis", "6 months minimum", "1 year after amputation"], correctIndex: 1, rationale: "Prosthetic fitting timeline: initial prosthesis may be fitted early (2-4 weeks), preparatory prosthesis when healed (4-8 weeks), and definitive prosthesis when volume stabilizes (3-6 months).", difficulty: 2, category: "Clinical Case Scenarios", topic: "prosthetic fitting timeline" },
  { id: "pta-1537", stem: "A patient with a sacral pressure injury (Stage 3) is receiving PT. What intervention is appropriate?", options: ["Only wound care", "Positioning program (pressure redistribution), progressive mobility, wound care within scope, and patient/caregiver education on skin inspection", "Only bed rest", "No PT role for pressure injuries"], correctIndex: 1, rationale: "Stage 3 pressure injury PT: positioning/turning program, pressure redistribution surfaces, progressive mobilization, wound care (within scope), and patient/caregiver education on skin protection.", difficulty: 2, category: "Clinical Case Scenarios", topic: "pressure injury PT" },
  { id: "pta-1538", stem: "A patient with bilateral transtibial amputations is learning to walk with bilateral prostheses. What is the gait training progression?", options: ["Immediate full ambulation", "Parallel bars → walker → bilateral crutches → bilateral canes → independent; starting with short distances and frequent rest breaks", "Only wheelchair training", "No progression — start with independent ambulation"], correctIndex: 1, rationale: "Bilateral BKA gait training: parallel bars (weight shifting, stepping) → walker → bilateral crutches → canes → independent. Short distances initially, progressive increase, and monitor vitals.", difficulty: 2, category: "Clinical Case Scenarios", topic: "bilateral BKA gait training" },
  { id: "pta-1539", stem: "A patient post-CABG surgery has sternal precautions. What activities should be avoided?", options: ["Walking", "Pushing, pulling, or lifting more than 5-10 lbs; no driving for 6-8 weeks; avoid activities that stress the sternum (reaching overhead with both arms)", "Deep breathing exercises", "Ankle pumps"], correctIndex: 1, rationale: "Sternal precautions: no pushing/pulling/lifting >5-10 lbs for 6-8 weeks, no driving, avoid bilateral overhead reaching, pillow support for coughing, and no unilateral UE weight-bearing.", difficulty: 1, category: "Clinical Case Scenarios", topic: "sternal precautions" },
  { id: "pta-1540", stem: "A patient with chronic kidney disease (on dialysis) is participating in PT. What exercise precaution applies?", options: ["No precautions", "Avoid exercising the arm with the arteriovenous (AV) fistula — no BP measurements, blood draws, or resistive exercise on that arm", "Exercise the fistula arm for strengthening", "Only exercise on dialysis days"], correctIndex: 1, rationale: "AV fistula precautions: no BP, no blood draws, no compression, no resistive exercise on the fistula arm. Avoid exercise immediately after dialysis (hypotension risk). Monitor BP/HR during exercise.", difficulty: 2, category: "Clinical Case Scenarios", topic: "dialysis exercise precautions" },
  { id: "pta-1541", stem: "A patient with rheumatoid arthritis has a flare-up with hot, swollen joints. What exercise is appropriate during a flare?", options: ["Aggressive strengthening", "Gentle AROM within pain-free range, isometrics, and avoid resistive exercises until inflammation subsides", "No exercise during flare", "Maximum resistance to strengthen"], correctIndex: 1, rationale: "RA flare exercise: gentle AROM (within pain-free range), low-intensity isometrics, avoid resistance training, rest inflamed joints, and continue as tolerated when inflammation subsides.", difficulty: 1, category: "Clinical Case Scenarios", topic: "RA flare exercise" },
  { id: "pta-1542", stem: "A patient with a total elbow replacement is at 6 weeks. What is the typical weight restriction?", options: ["No weight restriction", "Lifelong 5-10 lb lifting restriction on the affected arm to protect the prosthetic joint", "1-year restriction only", "Full weight allowed at 6 weeks"], correctIndex: 1, rationale: "Total elbow replacement: typically lifelong weight restriction of 5-10 lbs on the affected arm. Higher loads stress the prosthetic components and can lead to loosening or failure.", difficulty: 2, category: "Clinical Case Scenarios", topic: "elbow replacement restriction" },
  { id: "pta-1543", stem: "A PTA is treating a patient in a rural community with limited access to specialized rehabilitation. What telehealth application is appropriate?", options: ["No telehealth for PT", "Virtual exercise supervision, home program monitoring, patient education, and consultation with specialists via telehealth platforms", "Only in-person treatment", "Telehealth replaces all in-person care"], correctIndex: 1, rationale: "PT telehealth: virtual exercise supervision, HEP monitoring/progression, patient education, outcome measure administration, and remote consultation with specialists for rural/underserved populations.", difficulty: 1, category: "Professional Ethics", topic: "telehealth PT" },
  { id: "pta-1544", stem: "A patient with a recent knee arthroscopy is performing a short arc quad exercise (SAQ). What is the correct technique?", options: ["Full ROM knee extension", "Place a bolster under the knee (30-40° flexion), extend the knee from the bolster to full extension (last 30-40° of extension)", "Full ROM flexion and extension", "Leg curl exercise"], correctIndex: 1, rationale: "Short arc quad: bolster under the knee (30-40° flexion start position), actively extend to 0° (terminal extension). Targets VMO in the most functional range. Minimal patellofemoral stress.", difficulty: 1, category: "Therapeutic Exercises", topic: "SAQ technique" },
  { id: "pta-1545", stem: "A PTA is performing phonophoresis. What is this modality?", options: ["Electrical stimulation", "Use of ultrasound to drive a topical anti-inflammatory medication (like hydrocortisone) through the skin into deeper tissues", "Infrared therapy", "Magnetotherapy"], correctIndex: 1, rationale: "Phonophoresis: ultrasound-enhanced transdermal delivery of medication (typically hydrocortisone or NSAID gel). Continuous US at 1 MHz, 1.0-1.5 W/cm². The medication replaces the coupling gel.", difficulty: 2, category: "Therapeutic Exercises", topic: "phonophoresis" },
  { id: "pta-1546", stem: "A patient is performing a single-leg Romanian deadlift (RDL). Which muscles are primarily targeted?", options: ["Quadriceps", "Posterior chain: hamstrings, gluteus maximus, and erector spinae, with single-leg balance demand", "Chest and shoulders", "Hip adductors"], correctIndex: 1, rationale: "Single-leg RDL: targets posterior chain (hamstrings, glutes, erector spinae) with added proprioceptive and balance challenge. Functional exercise for hip hinge pattern and eccentric hamstring loading.", difficulty: 2, category: "Therapeutic Exercises", topic: "single-leg RDL" },
  { id: "pta-1547", stem: "A PTA is applying whirlpool therapy. What temperature range is used for a warm whirlpool?", options: ["60-70°F", "98-104°F (36.6-40°C) — comfortable warm temperature for wound care and general relaxation", "120°F+", "50-60°F"], correctIndex: 1, rationale: "Warm whirlpool: 98-104°F (36.6-40°C) for wound debridement, pain relief, and relaxation. Cold whirlpool: 55-65°F for acute injury. Neutral warmth: 92-96°F for exercise.", difficulty: 1, category: "Therapeutic Exercises", topic: "whirlpool temperature" },
  { id: "pta-1548", stem: "When applying TENS for chronic pain, what frequency and duration is typically used?", options: ["Very high frequency, 5 minutes", "Conventional TENS: high frequency (80-150 Hz), low intensity (sensory level), continuous, for 20-60 minutes or longer", "1 Hz for 2 minutes", "Maximum intensity, 5 minutes"], correctIndex: 1, rationale: "Conventional TENS for chronic pain: high frequency (80-150 Hz), low intensity (comfortable tingling), continuous mode, 20-60+ minutes. Can be worn for extended periods for ongoing relief.", difficulty: 2, category: "Therapeutic Exercises", topic: "conventional TENS parameters" },
  { id: "pta-1549", stem: "A PTA is performing soft tissue mobilization for a patient with plantar fasciitis. Where is the technique applied?", options: ["On the calf only", "Along the plantar fascia from the calcaneal attachment to the metatarsal heads, including the gastrocnemius-soleus complex", "On the ankle joint", "On the dorsum of the foot"], correctIndex: 1, rationale: "Plantar fasciitis STM: along the plantar fascia (calcaneus to metatarsal heads), into the intrinsic foot muscles, and the gastroc-soleus complex (continuous fascial connection).", difficulty: 1, category: "Therapeutic Exercises", topic: "plantar fascia STM" },
  { id: "pta-1550", stem: "A patient with a recent stroke is participating in body weight-supported treadmill training (BWSTT). What is the initial body weight support typically set at?", options: ["0% (full weight)", "30-40% body weight support initially, then gradually decrease as the patient improves gait performance", "80% support always", "5% only"], correctIndex: 1, rationale: "BWSTT initial support: 30-40% body weight reduction, allowing the patient to practice stepping with normal gait patterns. Gradually reduce support as gait improves (progress to 0%).", difficulty: 2, category: "Therapeutic Exercises", topic: "BWSTT parameters" },
  { id: "pta-1551", stem: "A patient is performing a standing hamstring curl with a resistance band. What type of contraction is occurring during the curl phase?", options: ["Eccentric", "Concentric contraction of the hamstrings (knee flexion against resistance)", "Isometric", "Isokinetic"], correctIndex: 1, rationale: "Standing hamstring curl: concentric contraction (muscle shortens) during knee flexion against resistance, eccentric contraction (controlled lowering) during return to extension.", difficulty: 1, category: "Therapeutic Exercises", topic: "hamstring curl contraction type" },
  { id: "pta-1552", stem: "A PTA is instructing a patient in diaphragmatic breathing. What cue helps the patient perform this correctly?", options: ["Only chest should rise", "Place one hand on the chest and one on the abdomen — the abdominal hand should rise while the chest hand stays relatively still", "Hold breath for 30 seconds", "Breathe as fast as possible"], correctIndex: 1, rationale: "Diaphragmatic breathing: hand on abdomen should rise (diaphragm descends), chest hand stays relatively still. Inhale through nose, exhale through pursed lips, 6-8 breaths per minute.", difficulty: 1, category: "Therapeutic Exercises", topic: "diaphragmatic breathing" },
  { id: "pta-1553", stem: "A patient needs a wheelchair cushion that maximizes pressure redistribution for high-risk skin. Which type is recommended?", options: ["Standard foam cushion", "Air flotation cushion (ROHO) — adjustable air cells conform to the individual's anatomy and distribute pressure evenly", "Gel cushion only", "No cushion"], correctIndex: 1, rationale: "High-risk skin: air flotation (ROHO) provides maximum pressure redistribution through interconnected air cells that conform to individual anatomy. Requires daily pressure checks.", difficulty: 2, category: "Assistive Devices", topic: "ROHO cushion" },
  { id: "pta-1554", stem: "A patient needs a knee immobilizer after an acute patellar dislocation. How long is it typically worn?", options: ["1 day", "2-4 weeks in full extension, then transition to a hinged knee brace with progressive ROM", "6 months", "Permanently"], correctIndex: 1, rationale: "Patellar dislocation: knee immobilizer in extension for 2-4 weeks, then hinged brace with progressive ROM. Quad strengthening (especially VMO), patellar mobilization, and proprioceptive training.", difficulty: 2, category: "Assistive Devices", topic: "patellar dislocation immobilizer" },
  { id: "pta-1555", stem: "When fitting axillary crutches, the top of the crutch should be positioned how many finger-widths below the axilla?", options: ["0 (touching the axilla)", "2-3 finger-widths below the axilla to prevent brachial plexus compression", "6 finger-widths", "It doesn't matter"], correctIndex: 1, rationale: "Axillary crutch fit: 2-3 finger-widths below the axilla, elbow flexed 20-30°, wrist in neutral. Weight on handgrips, NOT on the axillary pad (prevents brachial plexus compression).", difficulty: 1, category: "Assistive Devices", topic: "axillary crutch fitting" },
  { id: "pta-1556", stem: "A patient with a new hearing aid is having difficulty communicating during PT. What strategies improve communication?", options: ["Speak louder only", "Face the patient directly, reduce background noise, speak clearly at normal volume, and use visual cues/demonstration", "Write everything down", "Speak very slowly"], correctIndex: 1, rationale: "Hearing impairment communication: face the patient (lip reading), reduce background noise, speak clearly (don't shout), use gestures/demonstration, written communication as supplement.", difficulty: 1, category: "Patient Communication", topic: "hearing impairment communication" },
  { id: "pta-1557", stem: "A patient is frustrated with slow progress and wants to quit PT. How should the PTA respond?", options: ["Let the patient quit", "Acknowledge the frustration, review measurable progress made, relate progress to functional goals, and discuss modified expectations", "Ignore the frustration", "Tell the patient they must continue"], correctIndex: 1, rationale: "Frustration management: validate feelings, show objective progress (measurements), relate to functional goals, discuss realistic expectations, modify goals if needed, and motivate through achievable milestones.", difficulty: 1, category: "Patient Communication", topic: "managing patient frustration" },
  { id: "pta-1558", stem: "When communicating with a patient who has a visual impairment, what strategy should the PTA use?", options: ["Only use written instructions", "Identify yourself by name, describe the environment, use tactile cues for positioning, verbal description for exercises, and guide physically when appropriate", "Speak louder", "No special strategies needed"], correctIndex: 1, rationale: "Visual impairment communication: identify yourself, describe environment/equipment, verbal exercise descriptions, tactile guidance for positioning, and physical guidance for new movements.", difficulty: 1, category: "Patient Communication", topic: "visual impairment communication" },
  { id: "pta-1559", stem: "A PTA is collaborating with the patient's home health aide about a safe transfer technique. What information should be shared?", options: ["Only the diagnosis", "Specific transfer technique, weight-bearing status, assistive device use, level of assistance needed, and safety precautions", "Nothing — aides don't need clinical information", "Only the patient's name"], correctIndex: 1, rationale: "Home health aide communication: specific transfer technique, WB status, device use, assist level, safety precautions, skin care, and when to report changes. Demonstrate and have them return-demonstrate.", difficulty: 1, category: "Interdisciplinary Collaboration", topic: "aide transfer training" },
  { id: "pta-1560", stem: "The PTA receives a phone call from the patient's insurance company requesting clinical information. What is the correct response?", options: ["Share all information freely", "Verify the caller's identity, confirm there is a valid authorization for release, and share only information relevant to the clinical question", "Refuse all information", "Share only the diagnosis"], correctIndex: 1, rationale: "Insurance requests: verify caller identity, confirm authorization (HIPAA), share only relevant clinical information within the scope of the authorization, and document the communication.", difficulty: 1, category: "Professional Ethics", topic: "insurance information release" },
];
